package com.games.controller;import com.games.dto.LeaderboardEntry;import com.games.dto.MyStatsResponse;import com.games.entity.User;import com.games.service.LeaderboardService;import lombok.RequiredArgsConstructor;import org.springframework.http.ResponseEntity;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.CrossOrigin;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;import java.util.List;@RestController@RequestMapping("/api/leaderboard")@RequiredArgsConstructorpublic class LeaderboardController {    private final LeaderboardService leaderboardService;    /**     * GET /api/leaderboard     * Returns top 10 players by total score.     */    @GetMapping    public ResponseEntity<List<LeaderboardEntry>> getTop10() {        return ResponseEntity.ok(leaderboardService.getTop10());    }    /**     * GET /api/leaderboard/me     * Returns the authenticated user's full stats + streak.     */    @GetMapping("/me")    public ResponseEntity<MyStatsResponse> getMyStats(            @AuthenticationPrincipal User user) {        return ResponseEntity.ok(leaderboardService.getMyStats(user));    }}